CREATE OR REPLACE TEMPORARY TABLE mp_probe AS SELECT CASE WHEN (b.mp_base_marker IS NOT NULL AND lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND b.loaded_at IS NOT NULL AND date_diff('day', lk.lk_referral_date, b.loaded_at) >= $1 OR b.mp_base_marker IS NOT NULL AND lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND b.loaded_at IS NOT NULL AND date_diff('day', lk.lk_referral_date, b.loaded_at) < $2) THEN CAST(date_trunc('month', lk.lk_referral_date) AS DATE) ELSE NULL END AS event_month, CASE WHEN (b.mp_base_marker IS NOT NULL AND lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND b.loaded_at IS NOT NULL AND date_diff('day', lk.lk_referral_date, b.loaded_at) < $2) THEN $3 WHEN (b.mp_base_marker IS NOT NULL AND lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND b.loaded_at IS NOT NULL AND date_diff('day', lk.lk_referral_date, b.loaded_at) >= $1 AND date_diff('day', lk.lk_referral_date, b.loaded_at) > $4) THEN $5 WHEN (b.mp_base_marker IS NOT NULL AND lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND b.loaded_at IS NOT NULL AND date_diff('day', lk.lk_referral_date, b.loaded_at) >= $1 AND date_diff('day', lk.lk_referral_date, b.loaded_at) < $6) THEN $7 WHEN (b.mp_base_marker IS NOT NULL AND lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND b.loaded_at IS NOT NULL AND date_diff('day', lk.lk_referral_date, b.loaded_at) >= $1) THEN date_diff('day', lk.lk_referral_date, b.loaded_at) ELSE NULL END AS lag_day, CAST(b.loaded_at AS DATE) AS load_epoch_day, CAST(NULL AS VARCHAR) AS batch_id, CAST(NULL AS VARCHAR) AS alt_value, CASE WHEN (b.mp_base_marker IS NOT NULL AND lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND b.loaded_at IS NOT NULL AND date_diff('day', lk.lk_referral_date, b.loaded_at) >= $1) THEN $8 ELSE $9 END AS is_eligible, CASE WHEN (b.mp_base_marker IS NOT NULL AND lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NULL) THEN $10 ELSE $11 END AS is_null_event_time, CASE WHEN (b.mp_base_marker IS NOT NULL AND lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND b.loaded_at IS NULL) THEN $12 ELSE $13 END AS is_null_load_time_only, CASE WHEN (b.mp_base_marker IS NOT NULL AND lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND b.loaded_at IS NOT NULL AND date_diff('day', lk.lk_referral_date, b.loaded_at) >= $14 AND date_diff('day', lk.lk_referral_date, b.loaded_at) < $15) THEN $16 ELSE $17 END AS is_negative_clipped, CASE WHEN (b.mp_base_marker IS NOT NULL AND lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND b.loaded_at IS NOT NULL AND date_diff('day', lk.lk_referral_date, b.loaded_at) < $2) THEN $18 ELSE $19 END AS is_negative_lag_excluded, CASE WHEN (b.mp_base_marker IS NOT NULL AND lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND b.loaded_at IS NOT NULL AND date_diff('day', lk.lk_referral_date, b.loaded_at) >= $1 AND date_diff('day', lk.lk_referral_date, b.loaded_at) > $20) THEN $21 ELSE $22 END AS is_overflow, CASE WHEN (b.mp_base_marker IS NOT NULL AND lk.lk_matched IS NULL) THEN $23 ELSE $24 END AS is_join_unmatched, CASE WHEN (b.mp_base_marker IS NOT NULL AND (lk.lk_matched IS NULL OR lk.lk_rn = $25)) THEN $26 ELSE $27 END AS is_base_row, CASE WHEN (b.mp_base_marker IS NOT NULL AND lk.lk_rn = $28 AND lk.lk_dup > $29) THEN $30 ELSE $31 END AS is_ambiguous_base, CAST($32 AS INTEGER) AS is_compare_mismatch, CASE WHEN (b.mp_base_marker IS NOT NULL) THEN $33 ELSE $34 END AS is_probe_row, lk.lk_dup AS lookup_dup, CAST(NULL AS VARCHAR) AS key_hash, b.loaded_at AS load_time 
FROM (SELECT demo_health.dbo.episodes.loaded_at AS loaded_at, demo_health.dbo.episodes.referral_id AS referral_id, demo_health.dbo.episodes.site_code AS site_code, $35 AS mp_base_marker 
FROM demo_health.dbo.episodes) AS b FULL OUTER JOIN (SELECT demo_health.dbo.referrals.id AS lk_id, demo_health.dbo.referrals.referral_date AS lk_referral_date, demo_health.dbo.referrals.site AS lk_site, $36 AS lk_matched, count(*) OVER (PARTITION BY demo_health.dbo.referrals.id, demo_health.dbo.referrals.site) AS lk_dup, row_number() OVER (PARTITION BY demo_health.dbo.referrals.id, demo_health.dbo.referrals.site ORDER BY demo_health.dbo.referrals.id, demo_health.dbo.referrals.site) AS lk_rn 
FROM demo_health.dbo.referrals) AS lk ON b.referral_id = lk.lk_id AND b.site_code = lk.lk_site 
WHERE b.loaded_at <= $37 OR b.loaded_at IS NULL
